import type { ITreeItem, TreeSelectionEvent, TreeNode } from "@lmb-it/kitsconcerto-types";

export const buildTree: (
    data: Map<string | number, ITreeItem>,
    allowIndependentItems: boolean,
    parentKey?: null | string | number,
) => TreeNode[] = (data, allowIndependentItems = false, parentKey = null) => {
    const fetchedData = Array.from(data.values());

    // Process categorized items
    const categorized: TreeNode[] = fetchedData
        .filter(({ parentId }) => parentId === parentKey)
        .map((item, index) => {
            return {
                key: item.value.toString(),
                label: item.label,
                data: item,
                id: item.value.toString(),
                leaf: true,
                className: `node-${item.value.toString().split(".").join("_")}`,
                icon: item.isItem && !item?.data?.icon ? "pi pi-objects-column" : "",
                ...(item.selectable !== undefined && { selectable: item.selectable }),
                children: buildTree(data, allowIndependentItems, item.value),
            };
        });

    // If no parent category, process uncategorized items separately
    if (parentKey === null && !allowIndependentItems) {
        const uncategorized: TreeNode[] = fetchedData
            .filter((item) => item.isItem && !item.parentId)
            .map((item, index) => {
                return {
                    key: `uncategorized-${index}`,
                    label: item.label,
                    data: item,
                    id: item.value.toString(),
                    className: item.value.toString(),
                    children: [],
                };
            });

        if (uncategorized.length > 0) {
            categorized.push({
                key: "uncategorized",
                label: "Uncategorized",
                children: uncategorized,
            });
        }
    }

    return categorized;
};

/**
 * Mark a node's ancestors as partially or fully checked.
 * Moved from Selectable.tsx
 */
export function markAncestors(
    nodeId: number | string,
    nodes: Map<number | string, any>,
    selections: TreeSelectionEvent["value"],
) {
    const node = nodes.get(nodeId.toString());

    if (!node) {
        return;
    }

    const parentId = node.parentId;

    if (parentId === null || parentId === undefined) {
        return;
    }

    const parent = nodes.get(parentId.toString());

    if (!parent) {
        return;
    }
    if (!selections) {
        return;
    }
    const siblings = Array.from(nodes.values()).filter(
        (el) => el.parentId === parentId,
    );

    const allSiblingsChecked = siblings.every(
        // @ts-ignore
        (sibling) => selections[sibling.value]?.checked || false,
    );

    // If all siblings are checked, the parent is fully checked. Else, it is partially checked.
    // @ts-ignore
    selections[parentId] = { checked: allSiblingsChecked, partialChecked: true };

    // Call the function recursively for the parent.
    markAncestors(parentId, nodes, selections);
}
